import random
r = state.get('offer_batch')
if r and r != 0.0 and isinstance(r, list) and len(r) == 100:
  _result = r
else:
  _result = [{'price': 80+random.random()*400, 'duration': 0.5+random.random()*8, 'stops': random.randint(0,3)} for _ in range(100)]

offers = inputs.get('offer_batch')
if not offers or not isinstance(offers, list):
  _result = {'obs': [0.0,0.0,0.0,0.0], 'reward': 0.0, 'done': True, '_index': 0, '_selected': [], '_offers': []}
else:
  prev = state.get('filter_env')
  if prev is None or prev == 0.0 or not isinstance(prev, dict) or '_offers' not in prev:
    o = offers[0]
    obs = [o['price']/500.0, o['duration']/10.0, float(o['stops'])/3.0, 0.0]
    _result = {'obs': obs, 'reward': 0.0, 'done': False, '_index': 0, '_selected': [], '_offers': offers}
  else:
    idx = prev.get('_index', 0)
    sel = list(prev.get('_selected', [])) if isinstance(prev.get('_selected'), list) else []
    offs = prev.get('_offers', offers)
    act = inputs.get('rl_agent', 0.0)
    act = float(act[0]) if isinstance(act, (list, tuple)) and len(act) > 0 else float(act)
    if act > 0.5 and idx < len(offs):
      sel.append(idx)
    idx += 1
    if idx >= len(offs):
      reward = 0.0
      if sel:
        mean_p = sum(offs[i]['price'] for i in sel) / len(sel)
        reward = -mean_p / 500.0
        if 18 <= len(sel) <= 22:
          reward += 2.0
      _result = {'obs': [0.0,0.0,0.0,0.0], 'reward': reward, 'done': True, '_index': idx, '_selected': sel, '_offers': offs}
    else:
      o = offs[idx]
      obs = [o['price']/500.0, o['duration']/10.0, float(o['stops'])/3.0, idx/100.0]
      _result = {'obs': obs, 'reward': 0.0, 'done': False, '_index': idx, '_selected': sel, '_offers': offs}
